//
// customBuild: copy @earendil-works/pi-web-ui/dist/app.css verbatim to the
// agent/vendor/ resource tree, renamed to `pi_web_ui.css`. No Tailwind JIT
// run — pi-web-ui ships a pre-compiled Tailwind v4 bundle.

import { readFileSync, writeFileSync } from "node:fs";
import path from "node:path";

const vendorDir = process.env.VENDOR_DIR;
const outPath = process.env.ENTRY_OUT_PATH;
if (!vendorDir || !outPath) {
  throw new Error("pi-web-ui-css.build: expected VENDOR_DIR and ENTRY_OUT_PATH in env");
}

const src = path.join(
  vendorDir,
  "node_modules",
  "@earendil-works",
  "pi-web-ui",
  "dist",
  "app.css"
);
const body = readFileSync(src, "utf-8");
const header =
  "/* Copyright 2026 Dao Browser Authors. All rights reserved. */\n" +
  "/* Auto-generated by `npm run vendor -- --entry=pi-web-ui-css`. DO NOT EDIT. */\n" +
  "/* Source: @earendil-works/pi-web-ui/dist/app.css */\n";
writeFileSync(outPath, header + body, "utf-8");
